# Pod annotations — Vault Agent injects the secret automatically
annotations:
  vault.hashicorp.com/agent-inject:              "true"
  vault.hashicorp.com/role:                      "claude-api"
  vault.hashicorp.com/agent-inject-secret-api-key: "claude/data/api-key"
  vault.hashicorp.com/agent-inject-template-api-key: |
    {{- with secret "claude/data/api-key" -}}
    {{ .Data.data.value }}
    {{- end }}

# The key is written to /vault/secrets/api-key at startup
# Read it in Python:
import os

def get_key_from_vault_agent() -> str:
    with open("/vault/secrets/api-key") as f:
        return f.read().strip()
